scripts.script:
// -Drevision=... wins. session.userProperties holds CLI -D
// overrides; project.properties currently holds the POM default
// sentinel "0.0.0-no-git-tag". If the user passed -D, just
// propagate it into project.properties so flatten sees it.
def cli = session.userProperties.getProperty('revision')
if (cli != null && !cli.isEmpty()) {
    project.properties['revision'] = cli
    log.info("[derive-revision] using CLI -Drevision=" + cli)
} else {
    // Otherwise mirror palantir.git-version: a clean tag becomes
    // the bare tag, past-a-tag becomes "<tag>-<count>-g<sha>", and
    // uncommitted changes append ".dirty". `--always` falls back
    // to a short SHA if no tags exist (shallow clones, fresh
    // repos).
    try {
        def proc = ['git', 'describe', '--tags', '--dirty=.dirty', '--always'].execute(null, project.basedir)
        proc.waitForOrKill(5000)
        if (proc.exitValue() == 0) {
            def described = proc.text.trim()
            if (!described.isEmpty()) {
                project.properties['revision'] = described
                log.info("[derive-revision] resolved from git: " + described)
            } else {
                log.warn("[derive-revision] git describe empty output, keeping default revision=" + project.properties['revision'])
            }
        } else {
            log.warn("[derive-revision] git describe exit=" + proc.exitValue() + ", keeping default revision=" + project.properties['revision'])
        }
    } catch (Exception e) {
        log.warn("[derive-revision] git describe threw " + e.class.simpleName + ": " + e.message + ", keeping default revision=" + project.properties['revision'])
    }
}

// Derive a sanitized "revision.numeric" by stripping everything
// from the first - or +. jpackage on macOS rejects --app-version
// values containing anything other than N.N.N (no pre-release
// suffixes, no build metadata), so the mac and linux packaging
// profiles point at this property instead of ${project.version}.
// If -Drevision.numeric=... is passed explicitly on the CLI,
// respect that. The Windows profile keeps its own separate
// ${jpackage.app.version} mechanism (it has its own MSI major-
// <=255 constraint that needs 2-digit year handling, which the
// workflow already manages).
def cliNumeric = session.userProperties.getProperty('revision.numeric')
if (cliNumeric != null && !cliNumeric.isEmpty()) {
    project.properties['revision.numeric'] = cliNumeric
    log.info("[derive-revision] using CLI -Drevision.numeric=" + cliNumeric)
} else {
    def rev = project.properties['revision']
    def numeric = rev
    def dash = numeric.indexOf('-')
    if (dash >= 0) numeric = numeric.substring(0, dash)
    def plus = numeric.indexOf('+')
    if (plus >= 0) numeric = numeric.substring(0, plus)
    if (numeric.isEmpty()) numeric = '0.0.0'
    project.properties['revision.numeric'] = numeric
    if (numeric != rev) {
        log.warn("[derive-revision] revision \"" + rev + "\" has pre-release/build suffix; using \"" + numeric + "\" for jpackage --app-version. Pass -Drevision.numeric=N.N.N to override.")
    } else {
        log.info("[derive-revision] revision.numeric=" + numeric)
    }
}
